   * Returns a map where key is the digit sum and value is a sorted list of numbers
   * in [0, 5000] having that digit sum.
   * @return A map from digit sum to list of numbers.
   */
  def precalculateNumbers(): Map[Int, List[Int]] = {
    val maxVal = 5000
    val sums = mutable.Map[Int, mutable.ListBuffer[Int]]()

    for (i <- 0 to maxVal) {
      val s = sumDigits(i)
      sums.getOrElseUpdate(s, mutable.ListBuffer()) += i
    }

    sums.mapValues(_.toList.sorted)
  }

  /**
   * Solves the problem using Dynamic Programming.
   * @param digitSum The array of required digit sums.
   * @return The number of valid arrays modulo 10^9 + 7.
   */
  def solveDigitSum(digitSum: Array[Long]): Long = {
    val mod: Long = 1000000007L

