object Solution {
  // Helper function to calculate the sum of digits of a number
  def calculateDigitSum(n: Int): Int = {
    var num = n
    var sum = 0
    while (num > 0) {
      sum += num % 10
      num /= 10
    }
    sum
  }

  /**
    * Precomputes all numbers up to 5000 that have a specific digit sum.
    * Returns a map where key is the digit sum, and value is a sorted list of numbers.
    */
  def precomputeNumbers(maxVal: Int = 5000): Map[Int, Vector[Int]] = {
    val numbersByDigitSum = mutable.HashMap[Int, mutable.MutableList[Int]]()

    for (i <- 0 to maxVal) {
      val sum = calculateDigitSum(i)
      numbersByDigitSum.putIfAbsent(sum, mutable.mutable.ArrayBuffer[Int]())
      numbersByDigitSum(sum).add(i)
    }

    // Convert mutable lists to immutable Vectors and sort them
    numbersByDigitSum.mapValues(_.toVector.sorted).toMap
  }

  /**
    * Solves the problem using Dynamic Programming.
    * dp[i][j] = number of valid arrays of length i+1 ending with a number <= j.
    *
    * Since the constraints are N <= 1000 and digitSum[i] <= 50,
    * we will use a DP approach based on the index i and the value of the previous element arr[i-1].
    *
    * Let dp[i][prev_val] be the number of valid arrays of length i+1 such that arr[i] = prev_val.
    * This is too large because prev_val can be up to 5000.
    *
    * Let's re-examine the constraints and the structure.
    * We are looking for the number of sequences arr[0], arr[1], ..., arr[n-1] such that:
    * 1. 0 <= arr[i] <= 5000
    * 2. arr[i] is non-decreasing.
    * 3. digitSum(arr[i]) = digitSum[i].
    *
    * Let N be the length of digitSum.
    * Let S_i be the set of numbers <= 5000 such that digitSum(x) = digitSum[i].
    * We need to count sequences x_0, x_1, ..., x_{N-1} such that x_i in S_i, and x_i >= x_{i-1}.
    *
    * Since the sets S_i are pre-calculated, we can use DP on the indices of the sorted lists.
    *
    * Precomputation:
    * - `numMap`: Map from digit sum to sorted list of numbers in [0, 5000] with that sum.
    * - `S[i]`: The sorted list of possible values for arr[i].
    *
    * DP State:
    * dp[i][j]: The number of valid sequences arr[0], ..., arr[i] such that arr[i] is the j-th element in S[i] (i.e., arr[i] = S[i][j]).
    *
    * Transition:
    * dp[i][j] = sum(dp[i-1][k]) for all k such that S[i-1][k] <= S[i][j].
    *
    * Base Case:
    * For i = 0: dp[0][j] = 1 for all j (since any valid starting number forms a valid sequence of length 1).
    *
    * Final Answer:
    * Sum of all dp[N-1][j].
    */
  def solve(digitSum: Array[Long]): Long = {
    val N = digitSum.length
    val MOD: Long = 1000000000L + 7

    // Convert input to Int array as digit sums are small (<= 50)
    val digitSumInt = digitSum.map(_.toInt).toArray

    // Step 1: Precompute all valid numbers up to 5000
    val numMap = precomputeNumbers()

    // Step 2: Get the set of possible values S[i] for each index i
    val S = Array.ofDim[Vector[Int]](N)
    for (i <- 0 until N) {
      val requiredSum = digitSumInt(i)
      val possibleNums = numMap.getOrElse(requiredSum, Vector.empty[Int])
      if (possibleNums.isEmpty) {
        return 0 // Impossible to find any number for this digit sum
      }
      S(i) = possibleNums
    }

    // Step 3: Dynamic Programming
    // dp[i] is a vector where dp[i](j) is the count of valid sequences ending with S[i](j)
    // We only need the previous row, so we use two vectors: prevDP and currentDP.

    // Initial state (i = 0)
    // dp[0][j] = 1 for all j
    var prevDP = S(0).map(_ => 1L).toVector

    // Iterate from i = 1 to N-1
    for (i <- 1 until N) {
      val currentS = S(i)
      val prevS = S(i-1)
      val lenCurr = currentS.length
      val lenPrev = prevS.length

      var currentDP = mutable.ArrayBuffer[Long](lenCurr)

      // Optimization: Use prefix sums on the previous DP row to speed up summation
      // prefixSumPrev[k] = sum(prevDP[j] for j=0 to k)
      val prefixSumPrev = Array.ofDim[Long](lenPrev + 1)
      prefixSumPrev(0) = 0L
      for (k <- 0 until lenPrev) {
        prefixSumPrev(k + 1) = (prefixSumPrev(k) + prevDP(k)) % MOD
      }

      // Iterate through possible ending values for the current step (arr[i] = currentS(j))
      for (j <- 0 until lenCurr) {
        val currentValue = currentS(j)

        // We need to sum dp[i-1][k] for all k such that prevS(k) <= currentValue.

        // Find the maximum index k_max in prevS such that prevS(k_max) <= currentValue.
        // Since prevS is sorted, we can use binary search (or a simple linear scan if complexity allows, but binary search is cleaner).

        // Find the upper bound of currentValue in prevS
        var k_max = -1
        var low = 0
        var high = lenPrev - 1

        while (low <= high) {
          val mid = low + (high - low) / 2
          if (prevS(mid) <= currentValue) {
            k_max = mid
            low = mid + 1 // Try to find a larger index
          } else {
            high = mid - 1
          }
        }

        var sum = 0L
        if (k_max != -1) {
          // The sum required is sum(prevDP[k] for k=0 to k_max)
          // This is prefixSumPrev[k_max + 1]
          sum = prefixSumPrev(k_max + 1)
        }

        currentDP.append(sum)
      }

      // Move to the next iteration
      prevDP = currentDP.toVector
    }

    // Step 4: Final Result
    // The total count is the sum of all entries in the last DP row (prevDP holds dp[N-1])
    var totalCount = 0L
    for (count <- prevDP) {
      totalCount = (totalCount + count) % MOD
    }

    totalCount
  }
}
